+  return {
+    recipient: 'user-1',
+    subject: 'Order Confirmation: order-1',
+    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
+    notificationType: 'order_confirmation',
+    channel: 'webhook',
+    priority: 'normal',
+    metadata: { orderId: 'order-1', userId: 'user-1' },
+    ...overrides,
+  };
+}
+
+function createMockTransport(statusCode = 200) {
+  const sent: { url: string; payload: WebhookPayload; headers: Record<string, string> }[] = [];
+  const transport: WebhookTransport = {
+    async post(url, payload, headers) {
+      sent.push({ url, payload, headers });
+      return { statusCode };
+    },
+  };
+  return { transport, sent };
+}
