+    it('should format a notification payload into a webhook payload', () => {
+      const payload = makePayload();
+      const result = formatWebhookPayload(payload);
+
+      expect(result.event).toBe('order_confirmation');
+      expect(result.recipient).toBe('user-1');
+      expect(result.subject).toBe('Order Confirmation: order-1');
