+      const adapter = new WebhookAdapter({
+        url: 'https://example.com/hook',
+        transport,
+      });
+
+      const result = await adapter.send(makePayload());
+
+      expect(result.success).toBe(true);
+    });
+
+    it('should return failure when transport throws an Error', async () => {
+      const transport: WebhookTransport = {
+        async post() {
+          throw new Error('Connection refused');
+        },
+      };
+      const adapter = new WebhookAdapter({
+        url: 'https://example.com/hook',
+        transport,
+      });
+
+      const result = await adapter.send(makePayload());
+
+      expect(result.success).toBe(false);
+      expect(result.channel).toBe('webhook');
+      expect(result.error).toBe('Connection refused');
+    });
+
+    it('should handle non-Error throws gracefully', async () => {
+      const transport: WebhookTransport = {
+        async post() {
+          throw 'string error';
+        },
+      };
+      const adapter = new WebhookAdapter({
+        url: 'https://example.com/hook',
+        transport,
+      });
+
+      const result = await adapter.send(makePayload());
+
+      expect(result.success).toBe(false);
+      expect(result.error).toBe('Unknown webhook transport error');
+    });
+
+    it('should use logging transport when no transport is provided', async () => {
+      const adapter = new WebhookAdapter({ url: 'https://example.com/hook' });
+
+      const result = await adapter.send(makePayload());
+
+      expect(result.success).toBe(true);
+      expect(result.channel).toBe('webhook');
+    });
+
+    it('should send correct payload for different notification types', async () => {
+      const { transport, sent } = createMockTransport(200);
+      const adapter = new WebhookAdapter({
+        url: 'https://example.com/hook',
+        transport,
+      });
+
+      await adapter.send(
+        makePayload({
+          notificationType: 'welcome',
+          subject: 'Welcome!',
+          body: 'Welcome aboard!',
+          priority: 'high',
+          metadata: {},
+        }),
+      );
+
+      expect(sent[0]!.payload.event).toBe('welcome');
+      expect(sent[0]!.payload.subject).toBe('Welcome!');
+      expect(sent[0]!.payload.body).toBe('Welcome aboard!');
+      expect(sent[0]!.payload.priority).toBe('high');
+    });
+  });
+
+  describe('integration with NotificationService pattern', () => {
+    it('should conform to the NotificationAdapter interface', async () => {
+      const { transport } = createMockTransport(200);
+      const adapter = new WebhookAdapter({
+        url: 'https://example.com/hook',
+        transport,
+      });
+
+      // Verify it has the required shape
+      expect(adapter.channel).toBe('webhook');
+      expect(typeof adapter.send).toBe('function');
+
+      // Verify send returns the correct shape
+      const result = await adapter.send(makePayload());
+      expect(result).toHaveProperty('success');
+      expect(result).toHaveProperty('channel');
+    });
+
+    it('should be registrable with NotificationService', async () => {
+      // Import here to avoid circular dependency issues in test setup
+      const { EventBus } = await import('../../src/events/event-bus.js');
+      const { NotificationService } = await import('../../src/services/notification.service.js');
+
+      const { transport } = createMockTransport(200);
+      const adapter = new WebhookAdapter({
+        url: 'https://example.com/hook',
+        transport,
+      });
+
+      const eventBus = new EventBus();
+      const service = new NotificationService(eventBus);
+
+      // Should not throw
+      service.registerAdapter(adapter);
+    });
+  });
+});

