/**
 * Webhook notification adapter.
 *
 * Implements the NotificationAdapter interface for webhook delivery.
 * Formats notification payloads as JSON and POSTs them to a configured URL.
 *
 * CONSTRAINT: All adapters must implement the NotificationAdapter interface
 * from src/models/notification.ts. Register adapters with NotificationService
 * via registerAdapter().
 */

import type {
  NotificationAdapter,
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * The JSON body sent to the webhook endpoint.
 */
export interface WebhookPayload {
  event: string;
  recipient: string;
  subject: string;
  body: string;
  priority: string;
  metadata?: Record<string, string>;
  timestamp: string;
}

/**
 * Transport interface for sending HTTP requests.
 * Implement this for custom HTTP clients, or use the default fetch-based transport.
 */
export interface WebhookTransport {
  post(url: string, payload: WebhookPayload, headers: Record<string, string>): Promise<{ statusCode: number }>;
}

/**
 * Configuration for the webhook adapter.
 */
export interface WebhookAdapterConfig {
  /** The URL to POST webhook payloads to. */
  url: string;
  /** Optional secret used for signing or authorization headers. */
  secret?: string;
  /** Optional custom headers to include in webhook requests. */
  headers?: Record<string, string>;
  /** Webhook transport implementation. If not provided, uses a logging-only transport. */
  transport?: WebhookTransport;
}

/**
 * A logging-only transport used when no real transport is configured.
 * Useful for development and testing.
 */
class LoggingTransport implements WebhookTransport {
  private logger = new Logger('WebhookLoggingTransport');
  private sentPayloads: { url: string; payload: WebhookPayload; headers: Record<string, string> }[] = [];

  async post(url: string, payload: WebhookPayload, headers: Record<string, string>): Promise<{ statusCode: number }> {
    this.logger.info(`[DRY RUN] Webhook POST to=${url} event="${payload.event}"`);
    this.sentPayloads.push({ url, payload, headers });
    return { statusCode: 200 };
  }

  getSentPayloads() {
    return [...this.sentPayloads];
  }
}

/**
 * Format a NotificationPayload into the JSON body sent to the webhook endpoint.
 */
export function formatWebhookPayload(payload: NotificationPayload): WebhookPayload {
  return {
    event: payload.notificationType,
    recipient: payload.recipient,
    subject: payload.subject,
    body: payload.body,
    priority: payload.priority,
    metadata: payload.metadata,
    timestamp: new Date().toISOString(),
  };
}

export class WebhookAdapter implements NotificationAdapter {
  readonly channel = 'webhook' as const;
  private logger = new Logger('WebhookAdapter');
  private transport: WebhookTransport;

  constructor(private config: WebhookAdapterConfig) {
    this.transport = config.transport ?? new LoggingTransport();
  }

  /**
   * Build the headers for the webhook request.
   */
  private buildHeaders(): Record<string, string> {
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
      ...this.config.headers,
    };

    if (this.config.secret) {
      headers['Authorization'] = `Bearer ${this.config.secret}`;
    }

    return headers;
  }

  /**
   * Send a notification via webhook.
   *
   * Formats the notification as a JSON payload and POSTs it to the
   * configured webhook URL via the transport.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      const webhookPayload = formatWebhookPayload(payload);
      const headers = this.buildHeaders();

      this.logger.info(`Sending webhook to ${this.config.url}: event="${webhookPayload.event}"`);

      const result = await this.transport.post(this.config.url, webhookPayload, headers);

      if (result.statusCode >= 200 && result.statusCode < 300) {
        this.logger.info(`Webhook delivered successfully: statusCode=${result.statusCode}`);
        return {
          success: true,
          channel: this.channel,
        };
      }

      const errorMessage = `Webhook endpoint returned status ${result.statusCode}`;
      this.logger.error(errorMessage);
      return {
        success: false,
        channel: this.channel,
        error: errorMessage,
      };
    } catch (err: unknown) {
      const errorMessage = err instanceof Error ? err.message : 'Unknown webhook transport error';
      this.logger.error(`Failed to send webhook to ${this.config.url}: ${errorMessage}`);

      return {
        success: false,
        channel: this.channel,
        error: errorMessage,
      };
    }
  }
}

